--
-- Table structure for table `contracts`
--

DROP TABLE IF EXISTS `contracts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contracts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `contract_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `room_id` bigint unsigned NOT NULL,
  `start_date` date NOT NULL,
  `end_date` date DEFAULT NULL,
  `actual_end_date` date DEFAULT NULL,
  `billing_cycle_day` tinyint unsigned NOT NULL,
  `room_price` decimal(15,2) NOT NULL,
  `deposit_amount` decimal(15,2) NOT NULL,
  `status` tinyint unsigned NOT NULL DEFAULT '1',
  `tenant_signed_at` timestamp NULL DEFAULT NULL,
  `tenant_signature_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'signatures/placeholder.png',
  `payment_status` tinyint unsigned NOT NULL DEFAULT '1',
  `contract_files` json DEFAULT NULL,
  `note` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned DEFAULT NULL,
  `representative_tenant_id` bigint unsigned DEFAULT NULL,
  `parent_contract_id` bigint unsigned DEFAULT NULL,
  `renew_from_contract_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `contracts_contract_code_unique` (`contract_code`),
  KEY `contracts_room_id_foreign` (`room_id`),
  KEY `contracts_created_by_foreign` (`created_by`),
  KEY `contracts_parent_contract_id_foreign` (`parent_contract_id`),
  KEY `contracts_renew_from_contract_id_foreign` (`renew_from_contract_id`),
  KEY `contracts_representative_tenant_id_foreign` (`representative_tenant_id`),
  CONSTRAINT `contracts_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL,
  CONSTRAINT `contracts_parent_contract_id_foreign` FOREIGN KEY (`parent_contract_id`) REFERENCES `contracts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `contracts_renew_from_contract_id_foreign` FOREIGN KEY (`renew_from_contract_id`) REFERENCES `contracts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `contracts_representative_tenant_id_foreign` FOREIGN KEY (`representative_tenant_id`) REFERENCES `tenants` (`id`) ON DELETE SET NULL,
  CONSTRAINT `contracts_room_id_foreign` FOREIGN KEY (`room_id`) REFERENCES `rooms` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `contracts`
--

LOCK TABLES `contracts` WRITE;
/*!40000 ALTER TABLE `contracts` DISABLE KEYS */;
