--
-- Table structure for table `meter_devices`
--

DROP TABLE IF EXISTS `meter_devices`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `meter_devices` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `room_id` bigint unsigned NOT NULL,
  `service_id` bigint unsigned NOT NULL,
  `meter_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meter_type` tinyint unsigned NOT NULL DEFAULT '1',
  `initial_reading` decimal(12,2) NOT NULL,
  `installed_at` date DEFAULT NULL,
  `replaced_by_meter_id` bigint unsigned DEFAULT NULL,
  `status` tinyint unsigned NOT NULL DEFAULT '1',
  `image_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `note` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `meter_devices_meter_code_unique` (`meter_code`),
  KEY `meter_devices_room_id_foreign` (`room_id`),
  KEY `meter_devices_service_id_foreign` (`service_id`),
  KEY `meter_devices_replaced_by_meter_id_foreign` (`replaced_by_meter_id`),
  CONSTRAINT `meter_devices_replaced_by_meter_id_foreign` FOREIGN KEY (`replaced_by_meter_id`) REFERENCES `meter_devices` (`id`) ON DELETE SET NULL,
  CONSTRAINT `meter_devices_room_id_foreign` FOREIGN KEY (`room_id`) REFERENCES `rooms` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `meter_devices_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=135 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `meter_devices`
--

LOCK TABLES `meter_devices` WRITE;
/*!40000 ALTER TABLE `meter_devices` DISABLE KEYS */;
