--
-- Table structure for table `meter_readings`
--

DROP TABLE IF EXISTS `meter_readings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `meter_readings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `meter_device_id` bigint unsigned NOT NULL,
  `billing_month` tinyint unsigned NOT NULL,
  `billing_year` smallint unsigned NOT NULL,
  `previous_reading` decimal(12,2) NOT NULL,
  `current_reading` decimal(12,2) NOT NULL,
  `consumption` decimal(12,2) NOT NULL,
  `reading_date` date NOT NULL,
  `status` tinyint unsigned NOT NULL DEFAULT '1',
  `image_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `note` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `meter_readings_meter_device_id_billing_year_billing_month_unique` (`meter_device_id`,`billing_year`,`billing_month`),
  KEY `meter_readings_created_by_foreign` (`created_by`),
  CONSTRAINT `meter_readings_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL,
  CONSTRAINT `meter_readings_meter_device_id_foreign` FOREIGN KEY (`meter_device_id`) REFERENCES `meter_devices` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=129 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

