--
-- Table structure for table `room_movements`
--

DROP TABLE IF EXISTS `room_movements`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `room_movements` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `transfer_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tenant_id` bigint unsigned NOT NULL,
  `contract_id` bigint unsigned DEFAULT NULL,
  `source_contract_id` bigint unsigned DEFAULT NULL,
  `destination_contract_id` bigint unsigned DEFAULT NULL,
  `from_room_id` bigint unsigned DEFAULT NULL,
  `to_room_id` bigint unsigned DEFAULT NULL,
  `movement_type` tinyint unsigned NOT NULL DEFAULT '1',
  `status` tinyint unsigned NOT NULL DEFAULT '2',
  `movement_date` datetime NOT NULL,
  `old_room_final_amount` decimal(15,2) NOT NULL,
  `transfer_fee` decimal(15,2) NOT NULL,
  `deposit_transfer_amount` decimal(15,2) NOT NULL,
  `deposit_refund_amount` decimal(15,2) NOT NULL,
  `deduction_amount` decimal(15,2) NOT NULL,
  `manual_refund_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `deposit_due_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `extra_charge_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `settlement_due_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `settlement_paid_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `settlement_payment_status` tinyint unsigned NOT NULL DEFAULT '2',
  `settlement_payment_references` json DEFAULT NULL,
  `executed_at` timestamp NULL DEFAULT NULL,
  `failure_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `final_electric_reading` decimal(12,2) DEFAULT NULL,
  `final_water_reading` decimal(12,2) DEFAULT NULL,
  `note` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `scheduled_payload` json DEFAULT NULL,
  `created_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `room_movements_tenant_id_foreign` (`tenant_id`),
  KEY `room_movements_contract_id_foreign` (`contract_id`),
  KEY `room_movements_from_room_id_foreign` (`from_room_id`),
  KEY `room_movements_to_room_id_foreign` (`to_room_id`),
  KEY `room_movements_created_by_foreign` (`created_by`),
